// ---------------------------------------------------------------------------
// Lookup helpers (used by the advisor and the finder).
// ---------------------------------------------------------------------------
export function findRule(query) {
  const q = String(query ?? "").trim().toLowerCase();
  if (!q) return null;

  const exact =
    RULES.find((r) => r.slug === q) ||
    RULES.find((r) => r.name.toLowerCase() === q) ||
    RULES.find((r) => r.aliases.some((a) => a.toLowerCase() === q));
  if (exact) return exact;

  // Fuzzy stage: collect all includes-matches, then prefer entries whose name
  // STARTS with the query (generic entries over specific products), breaking
  // ties by shorter name — so "vitamins" → the general supplements entry,
  // not prenatal vitamins; "massage" → massage therapy, not massage guns.
  // The q.includes(alias) direction requires alias length ≥ 4 — otherwise
  // short aliases false-match inside words ("ot" inside "peloton").
  const fuzzy = RULES.filter(
    (r) =>
      r.name.toLowerCase().includes(q) ||
      r.aliases.some((a) => {
        const al = a.toLowerCase();
        return al.includes(q) || (al.length >= 4 && q.includes(al));
      })
  );
  if (!fuzzy.length) return null;
  fuzzy.sort((a, b) => {
    const aStarts = a.name.toLowerCase().startsWith(q) ? 0 : 1;
    const bStarts = b.name.toLowerCase().startsWith(q) ? 0 : 1;
    if (aStarts !== bStarts) return aStarts - bStarts;
    return a.name.length - b.name.length;
  });
  return fuzzy[0];
}

export function searchRules(query, limit = 8) {
  const q = String(query ?? "").trim().toLowerCase();
  if (!q) return [];
  const scored = RULES.map((r) => {
    let score = 0;
    if (r.name.toLowerCase().includes(q)) score += 3;
    if (r.slug.includes(q)) score += 2;
    if (r.aliases.some((a) => a.toLowerCase().includes(q))) score += 2;
    for (const word of q.split(/\s+/)) {
      if (word.length > 2 && (r.name.toLowerCase().includes(word) || r.aliases.some((a) => a.toLowerCase().includes(word)))) score += 1;
    }
    return { rule: r, score };
  })
    .filter((x) => x.score > 0)
    .sort((a, b) => b.score - a.score);
  return scored.slice(0, limit).map((x) => x.rule);
}
